// Sadə şərti tip
type IsString<T> = T extends string ? 'yes' : 'no';

type Test1 = IsString<string>; // 'yes'
type Test2 = IsString<number>; // 'no'

// Generic tiplərlə şərti tip
type ReturnTypeBasedOnInput<T> = T extends string ? string : number;

function processValue<T>(value: T): ReturnTypeBasedOnInput<T> {
  return typeof value === 'string' ? value.toUpperCase() : 42 as any;
}

let result1 = processValue('hello'); // string tipi, dəyər: 'HELLO'
let result2 = processValue(123); // number tipi, dəyər: 42
// let error = processValue(true); // Xəta: boolean ReturnTypeBasedOnInput ilə uyğun deyil

console.log(result1); // HELLO
console.log(result2); // 42

// Şərti tiplər və tip məhdudiyyətləri
type NonNullable<T> = T extends null | undefined ? never : T;

function getValue<T extends string | number>(value: T): NonNullable<T> {
  if (value == null) throw new Error('Null or undefined is not allowed');
  return value as NonNullable<T>;
}

let result1 = getValue('Hello'); // string tipi
let result2 = getValue(42); // number tipi
// let error = getValue(null); // Xəta: null NonNullable ilə uyğun deyil

console.log(result1); // Hello
console.log(result2); // 42

// Infer ilə şərti tip
type ElementType<T> = T extends (infer U)[] ? U : never;

type StringArrayElement = ElementType<string[]>; // string
type NumberArrayElement = ElementType<number[]>; // number
type Invalid = ElementType<string>; // never

// JavaScript-də oxşar kod
function processValueJS(value) {
  return typeof value === 'string' ? value.toUpperCase() : 42;
}

console.log(processValueJS('Hello')); // HELLO
console.log(processValueJS(123)); // 42
console.log(processValueJS(true)); // 42, lakin xəta yoxdur

// TypeScript-də təhlükəsiz kod
type ReturnTypeBasedOnInput<T> = T extends string ? string : number;

function processValueTS<T extends string | number>(value: T): ReturnTypeBasedOnInput<T> {
  return typeof value === 'string' ? value.toUpperCase() : 42 as any;
}

console.log(processValueTS('Hello')); // HELLO
console.log(processValueTS(123)); // 42
// console.log(processValueTS(true)); // Xəta: boolean ReturnTypeBasedOnInput ilə uyğun deyil

// Təhlükəsizlik nümunəsi
type GetReturnType<T> = T extends (...args: any[]) => infer R ? R : never;

function example(fn: () => string) {
  return fn();
}

type ExampleReturn = GetReturnType<typeof example>; // string

// Səhvə yol açan nümunə
function unsafeProcessValue(value: any): any {
  return typeof value === 'string' ? value.toUpperCase() : 42;
}

console.log(unsafeProcessValue('Hello')); // HELLO
console.log(unsafeProcessValue(123)); // 42
console.log(unsafeProcessValue(true)); // 42, lakin xəta yoxdur

// Düzgün yol
type ReturnTypeBasedOnInput<T> = T extends string ? string : number;

function safeProcessValue<T extends string | number>(value: T): ReturnTypeBasedOnInput<T> {
  return typeof value === 'string' ? value.toUpperCase() : 42 as any;
}

console.log(safeProcessValue('Hello')); // HELLO
console.log(safeProcessValue(123)); // 42
// console.log(safeProcessValue(true)); // Xəta: boolean ReturnTypeBasedOnInput ilə uyğun deyil

// Real layihə ssenarisi
type ApiResponseType<T> = T extends { error: string } ? { status: 'error'; message: string } : { status: 'success'; data: T };

interface User {
  id: number;
  name: string;
}
interface ErrorResponse {
  error: string;
}

function handleResponse<T>(response: T): ApiResponseType<T> {
  if ('error' in response) {
    return { status: 'error', message: (response as ErrorResponse).error } as ApiResponseType<T>;
  }
  return { status: 'success', data: response } as ApiResponseType<T>;
}

let success = handleResponse({ id: 1, name: 'Alice' });
let error = handleResponse({ error: 'Not found' });

console.log(success); // { status: 'success', data: { id: 1, name: 'Alice' } }
console.log(error); // { status: 'error', message: 'Not found' }

